1	package com.lunacode.skill;
2	
3	import com.fasterxml.jackson.databind.JsonNode;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.fasterxml.jackson.dataformat.yaml.YAMLFactory;
6	
7	import java.io.IOException;
8	import java.nio.file.Files;
9	import java.nio.file.Path;
10	import java.util.ArrayList;
11	import java.util.List;
12	import java.util.Optional;
13	import java.util.regex.Pattern;
14	
15	public final class FrontmatterSkillParser implements SkillParser {
16	    private static final Pattern NAME_PATTERN = Pattern.compile("^[a-z0-9][a-z0-9-]*$");
17	
18	    private final ObjectMapper yamlMapper = new ObjectMapper(new YAMLFactory());
19	
20	    @Override
21	    public SkillParseResult parseSingleFile(Path markdownFile, SkillOrigin origin) {
22	        try {
23	            return parseContent(Files.readString(markdownFile), origin, Optional.empty());
24	        } catch (IOException e) {
25	            return failure(origin, "无法读取 Skill 文件: " + e.getMessage());
26	        }
27	    }
28	
29	    @Override
30	    public SkillParseResult parseDirectory(Path skillDirectory, SkillOrigin origin) {
31	        Path entry = skillDirectory.resolve("SKILL.md");
32	        try {
33	            return parseContent(Files.readString(entry), origin, Optional.of(skillDirectory));
34	        } catch (IOException e) {
35	            return failure(origin, "无法读取目录型 Skill 入口: " + e.getMessage());
36	        }
37	    }
38	
39	    @Override
40	    public SkillParseResult parseBuiltin(String resourceName, String content, SkillOrigin origin) {
41	        return parseContent(content, origin, Optional.empty());
42	    }
43	
44	    private SkillParseResult parseContent(String content, SkillOrigin origin, Optional<Path> resourceRoot) {
45	        try {
46	            Frontmatter frontmatter = split(content == null ? "" : content);
47	            JsonNode root = yamlMapper.readTree(frontmatter.yaml());
48	            if (root == null || !root.isObject()) {
49	                return failure(origin, "frontmatter 必须是 YAML 对象");
50	            }
51	            String name = requiredText(root, "name");
52	            String description = requiredText(root, "description");
53	            if (!NAME_PATTERN.matcher(name).matches()) {
54	                return failure(origin, "Skill name 只能包含小写字母、数字和连字符: " + name);
55	            }
56	            SkillExecutionMode mode;
57	            SkillContextPolicy context;
58	            try {
59	                mode = SkillExecutionMode.fromFrontmatter(optionalText(root, "mode").orElse(null));
60	                context = SkillContextPolicy.fromFrontmatter(optionalText(root, "context").orElse(null));
61	            } catch (IllegalArgumentException e) {
62	                return failure(origin, e.getMessage());
63	            }
64	            List<String> tools = parseTools(root.path("tools"));
65	            SkillDefinition definition = new SkillDefinition(
66	                    name,
67	                    description,
68	                    mode,
69	                    context,
70	                    optionalText(root, "model"),
71	                    tools,
72	                    frontmatter.body(),
73	                    origin,
74	                    resourceRoot
75	            );
76	            return new SkillParseResult.Success(definition);
77	        } catch (IllegalArgumentException e) {
78	            return failure(origin, e.getMessage());
79	        } catch (IOException e) {
80	            return failure(origin, "frontmatter YAML 解析失败: " + e.getMessage());
81	        }
82	    }
83	
84	    private Frontmatter split(String content) {
85	        String normalized = content.replace("\r\n", "\n").replace('\r', '\n');
86	        if (!normalized.startsWith("---\n")) {
87	            throw new IllegalArgumentException("Skill 文件必须以 YAML frontmatter 开头");
88	        }
89	        int end = normalized.indexOf("\n---", 4);
90	        if (end < 0) {
91	            throw new IllegalArgumentException("Skill frontmatter 缺少结束分隔符");
92	        }
93	        int bodyStart = end + "\n---".length();
94	        if (bodyStart < normalized.length() && normalized.charAt(bodyStart) == '\n') {
95	            bodyStart++;
96	        }
97	        String yaml = normalized.substring(4, end);
98	        String body = bodyStart >= normalized.length() ? "" : normalized.substring(bodyStart);
99	        return new Frontmatter(yaml, body);
100	    }
101	
102	    private String requiredText(JsonNode root, String field) {
103	        Optional<String> value = optionalText(root, field);
104	        if (value.isEmpty()) {
105	            throw new IllegalArgumentException("Skill frontmatter 缺少必填字段: " + field);
106	        }
107	        return value.get();
108	    }
109	
110	    private Optional<String> optionalText(JsonNode root, String field) {
111	        JsonNode node = root.path(field);
112	        if (node.isMissingNode() || node.isNull()) {
113	            return Optional.empty();
114	        }
115	        if (!node.isTextual()) {
116	            throw new IllegalArgumentException("字段必须是字符串: " + field);
117	        }
118	        String value = node.asText().strip();
119	        return value.isBlank() ? Optional.empty() : Optional.of(value);
120	    }
121	
122	    private List<String> parseTools(JsonNode node) {
123	        if (node == null || node.isMissingNode() || node.isNull()) {
124	            return List.of();
125	        }
126	        if (!node.isArray()) {
127	            throw new IllegalArgumentException("tools 必须是字符串列表");
128	        }
129	        List<String> tools = new ArrayList<>();
130	        for (JsonNode item : node) {
131	            if (!item.isTextual()) {
132	                throw new IllegalArgumentException("tools 只能包含字符串");
133	            }
134	            String value = item.asText().strip();
135	            if (!value.isBlank()) {
136	                tools.add(value);
137	            }
138	        }
139	        return List.copyOf(tools);
140	    }
141	
142	    private SkillParseResult failure(SkillOrigin origin, String reason) {
143	        return new SkillParseResult.Failure(origin, reason);
144	    }
145	
146	    private record Frontmatter(String yaml, String body) {
147	    }
148	}

