9	
10	public final class FileSystemSkillSource implements SkillSource {
11	    public static final int PROJECT_PRIORITY = 300;
12	    public static final int USER_PRIORITY = 200;
13	
14	    private final SkillSourceKind kind;
15	    private final int priority;
16	    private final Path fixedRoot;
17	
18	    public FileSystemSkillSource(SkillSourceKind kind) {
19	        this(kind, null);
20	    }
21	
22	    public FileSystemSkillSource(SkillSourceKind kind, Path fixedRoot) {
23	        if (kind != SkillSourceKind.PROJECT && kind != SkillSourceKind.USER) {
24	            throw new IllegalArgumentException("文件系统来源只能是 PROJECT 或 USER");
25	        }
26	        this.kind = kind;
27	        this.priority = kind == SkillSourceKind.PROJECT ? PROJECT_PRIORITY : USER_PRIORITY;
28	        this.fixedRoot = fixedRoot == null ? null : fixedRoot.toAbsolutePath().normalize();
29	    }
30	
31	    public static FileSystemSkillSource project() {
32	        return new FileSystemSkillSource(SkillSourceKind.PROJECT);
33	    }
34	
35	    public static FileSystemSkillSource user() {
36	        return new FileSystemSkillSource(SkillSourceKind.USER);
37	    }
38	
39	    @Override
40	    public List<SkillCandidate> discover(Path projectRoot, Path userHome) {
41	        Path root = skillRoot(projectRoot, userHome);
42	        if (root == null || !Files.isDirectory(root)) {
43	            return List.of();
44	        }
45	        List<SkillCandidate> candidates = new ArrayList<>();
46	        try (var stream = Files.list(root)) {
47	            List<Path> children = stream
48	                    .sorted(Comparator.comparing(path -> path.getFileName().toString()))
49	                    .toList();
50	            for (Path child : children) {
51	                if (Files.isRegularFile(child) && child.getFileName().toString().endsWith(".md")) {
52	                    candidates.add(SkillCandidate.singleFile(child, origin(child)));
53	                    continue;
54	                }
55	                if (Files.isDirectory(child) && Files.isRegularFile(child.resolve("SKILL.md"))) {
56	                    candidates.add(SkillCandidate.directory(child, origin(child.resolve("SKILL.md"))));
57	                }
58	            }
59	        } catch (IOException ignored) {
60	            return List.of();
61	        }
62	        return List.copyOf(candidates);
63	    }
64	
65	    private Path skillRoot(Path projectRoot, Path userHome) {
66	        if (fixedRoot != null) {
67	            return fixedRoot;
68	        }
69	        return switch (kind) {
70	            case PROJECT -> projectRoot == null ? null : projectRoot.resolve(".lunacode").resolve("skills");
71	            case USER -> userHome == null ? null : userHome.resolve(".lunacode").resolve("skills");
72	            case BUILTIN -> null;
73	        };
74	    }
75	
76	    private SkillOrigin origin(Path path) {
77	        Path normalized = path.toAbsolutePath().normalize();
78	        return new SkillOrigin(kind, normalized.toString(), java.util.Optional.of(normalized), priority);
79	    }
80	}

