5	public enum SkillExecutionMode {
6	    INLINE,
7	    FORK;
8	
9	    public static SkillExecutionMode fromFrontmatter(String value) {
10	        if (value == null || value.isBlank()) {
11	            return INLINE;
12	        }
13	        return switch (value.strip().toLowerCase(Locale.ROOT)) {
14	            case "inline" -> INLINE;
15	            case "fork" -> FORK;
16	            default -> throw new IllegalArgumentException("invalid mode: " + value);
17	        };
18	    }
19	}

