8	import java.util.Optional;
9	
10	import static org.junit.jupiter.api.Assertions.assertEquals;
11	import static org.junit.jupiter.api.Assertions.assertInstanceOf;
12	import static org.junit.jupiter.api.Assertions.assertTrue;
13	
14	class FrontmatterSkillParserTest {
15	    @TempDir
16	    Path tempDir;
17	
18	    private final FrontmatterSkillParser parser = new FrontmatterSkillParser();
19	
20	    @Test
21	    void parsesSingleFileWithDefaults() throws Exception {
22	        Path file = tempDir.resolve("commit.md");
23	        Files.writeString(file, """
24	                ---
25	                name: commit
26	                description: 生成提交信息
27	                ---
28	                请生成 commit。
29	                """);
30	
31	        SkillDefinition definition = success(parser.parseSingleFile(file, origin(file)));
32	
33	        assertEquals("commit", definition.name());
34	        assertEquals("生成提交信息", definition.description());
35	        assertEquals(SkillExecutionMode.INLINE, definition.mode());
36	        assertEquals(SkillContextPolicy.FULL, definition.context());
37	        assertTrue(definition.tools().isEmpty());
38	        assertTrue(definition.model().isEmpty());
39	        assertTrue(definition.body().contains("请生成 commit"));
40	    }
41	
42	    @Test
43	    void parsesDirectorySkillWithResourceRoot() throws Exception {
44	        Path dir = tempDir.resolve("backend-interview");
45	        Files.createDirectories(dir);
46	        Files.writeString(dir.resolve("SKILL.md"), """
47	                ---
48	                name: backend-interview
49	                description: 面试题生成
50	                mode: fork
51	                context: recent
52	                tools:
53	                  - ReadFile
54	                model: luna-strong
55	                ---
56	                读取 examples/sample.md。
57	                """);
58	
59	        SkillDefinition definition = success(parser.parseDirectory(dir, origin(dir.resolve("SKILL.md"))));
60	
61	        assertEquals(SkillExecutionMode.FORK, definition.mode());
62	        assertEquals(SkillContextPolicy.RECENT, definition.context());
63	        assertEquals(Optional.of("luna-strong"), definition.model());
64	        assertEquals(java.util.List.of("ReadFile"), definition.tools());
65	        assertEquals(dir.toAbsolutePath().normalize(), definition.resourceRoot().orElseThrow());
66	    }
67	
68	    @Test
69	    void rejectsMissingRequiredFieldsAndInvalidValues() throws Exception {
70	        assertFailure("""
71	                ---
72	                description: 缺名称
73	                ---
74	                body
75	                """);
76	        assertFailure("""
77	                ---
78	                name: missing-description
79	                ---
80	                body
81	                """);
82	        assertFailure("""
83	                ---
84	                name: BadName
85	                description: 非法名称
86	                ---
87	                body
88	                """);
89	        assertFailure("""
90	                ---
91	                name: bad-mode
92	                description: 非法模式
93	                mode: async
94	                ---
95	                body
96	                """);
97	        assertFailure("""
98	                ---
99	                name: bad-context
100	                description: 非法上下文
101	                context: latest
102	                ---
103	                body
104	                """);
105	    }
106	
107	    @Test
108	    void rejectsMissingFrontmatter() throws Exception {
109	        Path file = tempDir.resolve("bad.md");
110	        Files.writeString(file, "no frontmatter");
111	
112	        assertInstanceOf(SkillParseResult.Failure.class, parser.parseSingleFile(file, origin(file)));
113	    }
114	
115	    private void assertFailure(String content) throws Exception {
116	        Path file = tempDir.resolve("skill-" + System.nanoTime() + ".md");
117	        Files.writeString(file, content);
118	        assertInstanceOf(SkillParseResult.Failure.class, parser.parseSingleFile(file, origin(file)));
119	    }
120	
121	    private SkillDefinition success(SkillParseResult result) {
122	        return assertInstanceOf(SkillParseResult.Success.class, result).definition();
123	    }
124	
125	    private SkillOrigin origin(Path path) {
126	        return new SkillOrigin(SkillSourceKind.PROJECT, path.toString(), Optional.of(path), 300);
127	    }
128	}

