3	import java.io.IOException;
4	import java.nio.charset.StandardCharsets;
5	import java.util.ArrayList;
6	import java.util.List;
7	
8	public final class BuiltinSkillSource implements SkillSource {
9	    public static final int BUILTIN_PRIORITY = 100;
10	
11	    private final ClassLoader classLoader;
12	    private final List<String> resources;
13	
14	    public BuiltinSkillSource() {
15	        this(BuiltinSkillSource.class.getClassLoader(), List.of(
16	                "lunacode/skills/commit.md",
17	                "lunacode/skills/test.md"
18	        ));
19	    }
20	
21	    public BuiltinSkillSource(ClassLoader classLoader, List<String> resources) {
22	        this.classLoader = classLoader == null ? BuiltinSkillSource.class.getClassLoader() : classLoader;
23	        this.resources = resources == null ? List.of() : List.copyOf(resources);
24	    }
25	
26	    @Override
27	    public List<SkillCandidate> discover(java.nio.file.Path projectRoot, java.nio.file.Path userHome) {
28	        List<SkillCandidate> candidates = new ArrayList<>();
29	        for (String resource : resources) {
30	            try (var stream = classLoader.getResourceAsStream(resource)) {
31	                if (stream == null) {
32	                    continue;
33	                }
34	                String content = new String(stream.readAllBytes(), StandardCharsets.UTF_8);
35	                SkillOrigin origin = new SkillOrigin(
36	                        SkillSourceKind.BUILTIN,
37	                        resource,
38	                        java.util.Optional.empty(),
39	                        BUILTIN_PRIORITY
40	                );
41	                candidates.add(SkillCandidate.builtin(resource, content, origin));
42	            } catch (IOException ignored) {
43	                // 单个内置资源异常只跳过该资源，保持其余 Skill 可用。
44	            }
45	        }
46	        return List.copyOf(candidates);
47	    }
48	}

