/* ============================================
   毛毛商店 — Pet Shop Product Listing
   设计系统：简约干净 · 鼠尾草绿 · 暖橙点缀
   ============================================ */

/* --- 设计令牌 --- */
:root {
  --bg: #FAFAF8;
  --bg-card: #FFFFFF;
  --text-primary: #1E1E1E;
  --text-secondary: #8A8A8A;
  --brand: #4B8B7A;
  --brand-light: rgba(75, 139, 122, 0.08);
  --accent: #D4845A;
  --border: #E8E6E1;
  --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.04);
  --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.06);
  --radius-sm: 8px;
  --radius-md: 12px;
  --font-display: 'Plus Jakarta Sans', system-ui, sans-serif;
  --font-body: 'Inter', system-ui, sans-serif;
}

/* --- Reset & Base --- */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-body);
  font-weight: 400;
  font-size: 15px;
  line-height: 1.5;
  color: var(--text-primary);
  background: var(--bg);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* --- 顶部导航 --- */
.header {
  position: sticky;
  top: 0;
  z-index: 10;
  background: rgba(250, 250, 248, 0.85);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border);
}

.header__inner {
  max-width: 1024px;
  margin: 0 auto;
  padding: 14px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.logo {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 18px;
  color: var(--text-primary);
  text-decoration: none;
  display: flex;
  align-items: center;
  gap: 10px;
}

.logo__mark {
  display: block;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--brand);
  flex-shrink: 0;
}

.header__actions {
  display: flex;
  gap: 8px;
}

.icon-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  border: none;
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--text-primary);
  cursor: pointer;
  transition: background 0.2s, color 0.2s;
}

.icon-btn:hover {
  background: var(--brand-light);
  color: var(--brand);
}

/* --- 分类标签 --- */
.categories {
  border-bottom: 1px solid var(--border);
}

.categories__inner {
  max-width: 1024px;
  margin: 0 auto;
  padding: 12px 20px;
  display: flex;
  gap: 8px;
  overflow-x: auto;
  scrollbar-width: none;
  -ms-overflow-style: none;
}

.categories__inner::-webkit-scrollbar {
  display: none;
}

.pill {
  flex-shrink: 0;
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: 500;
  padding: 6px 16px;
  border: 1px solid var(--border);
  border-radius: 100px;
  background: transparent;
  color: var(--text-secondary);
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
}

.pill:hover {
  border-color: var(--brand);
  color: var(--brand);
  background: var(--brand-light);
}

.pill--active {
  border-color: var(--brand);
  background: var(--brand);
  color: #fff;
}

/* --- 商品网格 --- */
.main {
  flex: 1;
}

.products {
  max-width: 1024px;
  margin: 0 auto;
  padding: 24px 20px 48px;
}

.products__grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 20px;
}

/* --- 商品卡片 --- */
.product-card {
  background: var(--bg-card);
  border-radius: var(--radius-md);
  overflow: hidden;
  box-shadow: var(--shadow-sm);
  transition: box-shadow 0.3s, transform 0.3s;
  cursor: pointer;
}

.product-card:hover {
  box-shadow: var(--shadow-md);
  transform: translateY(-2px);
}

.product-card__image-wrap {
  position: relative;
  aspect-ratio: 4 / 3;
  overflow: hidden;
  background: #F3F0EC;
}

.product-card__image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  transition: transform 0.4s ease;
}

.product-card:hover .product-card__image {
  transform: scale(1.03);
}

/* 悬停蒙层 + Quick view */
.product-card__overlay {
  position: absolute;
  inset: 0;
  background: rgba(75, 139, 122, 0.06);
  opacity: 0;
  transition: opacity 0.3s;
}

.product-card:hover .product-card__overlay {
  opacity: 1;
}

.product-card__quick-view {
  position: absolute;
  bottom: 12px;
  left: 12px;
  font-family: var(--font-body);
  font-size: 12px;
  font-weight: 500;
  color: var(--brand);
  background: rgba(255, 255, 255, 0.9);
  padding: 4px 12px;
  border-radius: 100px;
  opacity: 0;
  transform: translateY(6px);
  transition: opacity 0.3s, transform 0.3s;
}

.product-card:hover .product-card__quick-view {
  opacity: 1;
  transform: translateY(0);
}

.product-card__info {
  padding: 14px 16px 16px;
}

.product-card__category {
  font-size: 12px;
  font-weight: 500;
  color: var(--text-secondary);
  letter-spacing: 0.3px;
  margin-bottom: 4px;
}

.product-card__name {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 16px;
  color: var(--text-primary);
  line-height: 1.3;
  margin-bottom: 8px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.product-card__price {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 17px;
  color: var(--accent);
}

/* --- 底部 --- */
.footer {
  border-top: 1px solid var(--border);
  margin-top: auto;
}

.footer__inner {
  max-width: 1024px;
  margin: 0 auto;
  padding: 20px;
  text-align: center;
}

.footer__text {
  font-size: 13px;
  color: var(--text-secondary);
}

/* --- 响应式 --- */
@media (max-width: 640px) {
  .products__grid {
    gap: 12px;
  }

  .product-card__info {
